import React, { useState, useEffect } from 'react';
import './LoginForm.css';

// ─── Provider brand icons ─────────────────────────────────────────────────────

const GoogleIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" aria-hidden="true">
    <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
    <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
    <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"/>
    <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
  </svg>
);

const GitHubIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" aria-hidden="true" fill="currentColor">
    <path d="M12 .297c-6.63 0-12 5.373-12 12 0 5.303 3.438 9.8 8.205 11.385.6.113.82-.258.82-.577 0-.285-.01-1.04-.015-2.04-3.338.724-4.042-1.61-4.042-1.61C4.422 18.07 3.633 17.7 3.633 17.7c-1.087-.744.084-.729.084-.729 1.205.084 1.838 1.236 1.838 1.236 1.07 1.835 2.809 1.305 3.495.998.108-.776.417-1.305.76-1.605-2.665-.3-5.466-1.332-5.466-5.93 0-1.31.465-2.38 1.235-3.22-.135-.303-.54-1.523.105-3.176 0 0 1.005-.322 3.3 1.23.96-.267 1.98-.399 3-.405 1.02.006 2.04.138 3 .405 2.28-1.552 3.285-1.23 3.285-1.23.645 1.653.24 2.873.12 3.176.765.84 1.23 1.91 1.23 3.22 0 4.61-2.805 5.625-5.475 5.92.42.36.81 1.096.81 2.22 0 1.606-.015 2.896-.015 3.286 0 .315.21.69.825.57C20.565 22.092 24 17.592 24 12.297c0-6.627-5.373-12-12-12"/>
  </svg>
);

const SOCIAL_PROVIDERS = [
  { id: 'google', label: 'Google', Icon: GoogleIcon },
  { id: 'github', label: 'GitHub', Icon: GitHubIcon },
];

// ─── Component ────────────────────────────────────────────────────────────────

const LoginForm = ({ onLogin, onSwitchToSignup, onSocialLogin, isDarkMode, initialError }) => {
  const [credentials, setCredentials] = useState({
    email: '',
    password: ''
  });
  const [isLogging, setIsLogging] = useState(false);
  const [socialLoading, setSocialLoading] = useState(null); // which provider is in-flight
  const [errors, setErrors] = useState(initialError ? { form: initialError } : {});

  // Apply dark mode to document even on login screen
  useEffect(() => {
    console.log('🔑 Login form mounted and ready');
    document.documentElement.setAttribute('data-theme', isDarkMode ? 'dark' : 'light');
  }, [isDarkMode]);

  const validateForm = () => {
    const newErrors = {};
    
    if (!credentials.email) {
      newErrors.email = 'Email is required';
    } else if (!/\S+@\S+\.\S+/.test(credentials.email)) {
      newErrors.email = 'Email is invalid';
    }
    
    if (!credentials.password) {
      newErrors.password = 'Password is required';
    } else if (credentials.password.length < 6) {
      newErrors.password = 'Password must be at least 6 characters';
    }
    
    return newErrors;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formErrors = validateForm();
    
    if (Object.keys(formErrors).length > 0) {
      setErrors(formErrors);
      return;
    }
    
    setIsLogging(true);
    setErrors({});

    try {
      await onLogin(credentials);
    } catch (err) {
      setErrors({ form: err.message || 'Login failed. Please check your credentials.' });
    } finally {
      setIsLogging(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setCredentials(prev => ({
      ...prev,
      [name]: value
    }));
    // Clear error when user starts typing
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  const handleSocialLogin = (provider) => {
    setSocialLoading(provider);
    setErrors({});
    // Redirect browser to backend OAuth start - backend handles the full provider flow and
    // redirects back to this page with ?_oauthToken=<JWT> after successful authentication.
    const apiBase = process.env.REACT_APP_API_URL || 'https://api.nebula3ddev.com/api';
    const appUrl = encodeURIComponent(window.location.origin + window.location.pathname);
    window.location.href = `${apiBase}/auth/oauth/${provider}/start?app_url=${appUrl}`;
  };

  const isBusy = isLogging || socialLoading !== null;

  return (
    <div className={`login-container ${isDarkMode ? 'dark-mode' : ''}`}>
      <div className="login-form">
        <div className="login-header">
          <h1>🛡️ Nebula VPN</h1>
          <p>Secure your connection</p>
        </div>

        {/* Social sign-in buttons */}
        <div className="social-login-section">
          {SOCIAL_PROVIDERS.map(({ id, label, Icon }) => (
            <button
              key={id}
              type="button"
              className={`social-login-btn social-login-btn--${id}`}
              onClick={() => handleSocialLogin(id)}
              disabled={isBusy}
              aria-label={`Sign in with ${label}`}
            >
              {socialLoading === id ? (
                <span className="social-spinner" aria-hidden="true" />
              ) : (
                <Icon />
              )}
              <span>{socialLoading === id ? `Connecting…` : `Continue with ${label}`}</span>
            </button>
          ))}
        </div>

        <div className="login-divider">
          <span>OR SIGN IN WITH EMAIL</span>
        </div>
        
        <form onSubmit={handleSubmit}>
          {errors.form && (
            <div className="form-error-banner">{errors.form}</div>
          )}
          <div className="form-group">
            <input
              type="email"
              name="email"
              placeholder="Email"
              value={credentials.email}
              onChange={handleChange}
              className={errors.email ? 'error' : ''}
            />
            {errors.email && <span className="error-text">{errors.email}</span>}
          </div>
          
          <div className="form-group">
            <input
              type="password"
              name="password"
              placeholder="Password"
              value={credentials.password}
              onChange={handleChange}
              className={errors.password ? 'error' : ''}
            />
            {errors.password && <span className="error-text">{errors.password}</span>}
          </div>
          
          <button 
            type="submit" 
            className="login-btn"
            disabled={isBusy}
          >
            {isLogging ? 'Logging in…' : 'Login'}
          </button>
        </form>
        
        <div className="login-footer">
          <p>Don't have an account? 
            <button 
              type="button"
              className="signup-link" 
              onClick={onSwitchToSignup}
            >
              Sign up
            </button>
          </p>
        </div>
      </div>
    </div>
  );
};

export default LoginForm;
